4362	\begin{lemma}[$\top$-level semilinearity of the section transport (producer, c)]
4363	  \label{lem:gamma_image_iso_semilinear_top}
4364	  \lean{AlgebraicGeometry.Scheme.Modules.gamma_image_iso_semilinear_top}
4365	  \uses{lem:gamma_pullback_image_iso_hom_semilinear, def:gamma_image_ring_equiv,
4366	    lem:gamma_pullback_image_iso_hom_naturality, lem:composite_immersion_flocus_basicOpen}
4367	  \textit{Project-bespoke: upgrades the $D(f')$-level semilinearity to the $\top$-level $\sigma$.}
4368	  The section transports \cref{lem:gamma_pullback_image_iso} (forward maps), which are semilinear over
4369	  the \(D(f')\)-level ring iso \(\mathrm{gammaImageRingEquiv}\,j\,D(f')\)
4370	  (\cref{lem:gamma_pullback_image_iso_hom_semilinear}), are also semilinear over the \(\top\)-level ring
4371	  iso \(\sigma = \mathrm{gammaImageRingEquiv}\,j\,\top\) of
4372	  \cref{lem:composite_immersion_flocus_basicOpen}, as required for the \(R_s\)-actions fed to the
4373	  combiner.
4374	\end{lemma}
4375	\begin{proof}
4376	  \uses{lem:gamma_pullback_image_iso_hom_semilinear, lem:gamma_pullback_image_iso_hom_naturality,
4377	    def:gamma_image_ring_equiv}
4378	  The structure-sheaf restriction \(\Gamma(\mathcal{O}_{\Spec R_s}, \top) \to \Gamma(\mathcal{O}_{\Spec
4379	  R_s}, D(f'))\) intertwines the two ring isos \(\sigma\) and \(\mathrm{gammaImageRingEquiv}\,j\,D(f')\)
4380	  (naturality of \(\mathrm{gammaImageRingEquiv}\) in the open argument), and the section transports at
4381	  \(\top\) and \(D(f')\) commute with the module restriction maps
4382	  (\cref{lem:gamma_pullback_image_iso_hom_naturality}); transporting the \(D(f')\)-level semilinearity
4383	  \cref{lem:gamma_pullback_image_iso_hom_semilinear} along this restriction yields the \(\top\)-level
4384	  semilinearity over \(\sigma\).
4385	\end{proof}
