4387	\begin{lemma}[$A$-module and scalar-tower instances on the $f$-locus sections (producer, d)]
4388	  \label{lem:flocus_section_scalar_tower}
4389	  \lean{AlgebraicGeometry.Scheme.Modules.flocus_section_scalar_tower}
4390	  \uses{def:gamma_image_ring_equiv, lem:composite_immersion_flocus_basicOpen}
4391	  \textit{Project-bespoke: the $A$-module / $\mathrm{IsScalarTower}$ instances feeding the combiner.}
4392	  Let \(A = \Gamma(M, D(s))\) and consider the \(f\)-locus sections \(\Gamma(M, j\,''^{U}\,D(f')) =
4393	  \Gamma(M, D(f) \sqcap D(s))\). These carry an \(A\)-module structure and an \(R\)-module structure with
4394	  \(\mathrm{IsScalarTower}\,R\,A\,\Gamma(M, D(f) \sqcap D(s))\), where the \(A\)-action is by restriction
4395	  of the structure-sheaf action along \(\Gamma(\mathcal{O}_{\Spec R}, D(s)) \to \Gamma(\mathcal{O}_{\Spec
4396	  R}, D(f) \sqcap D(s))\), and likewise for the source \(\Gamma(M, D(s))\).
4397	\end{lemma}
4398	\begin{proof}
4399	  \uses{lem:composite_immersion_flocus_basicOpen}
4400	  The module \(\Gamma(M, D(f) \sqcap D(s))\) is a module over the section ring
4401	  \(\Gamma(\mathcal{O}_{\Spec R}, D(f) \sqcap D(s))\); restriction of scalars along the structure-sheaf
4402	  restriction \(\Gamma(\mathcal{O}_{\Spec R}, D(s)) \to \Gamma(\mathcal{O}_{\Spec R}, D(f) \sqcap D(s))\)
4403	  makes it an \(A\)-module, and along \(R \to \Gamma(\mathcal{O}_{\Spec R}, D(s)) = A\) an \(R\)-module;
4404	  the scalar tower \(\mathrm{IsScalarTower}\,R\,A\,\Gamma(M, D(f) \sqcap D(s))\) is the factorization of
4405	  the two ring maps. The identification of the locus \(j\,''^{U}\,D(f') = D(f) \sqcap D(s)\) is
4406	  \cref{lem:composite_immersion_flocus_basicOpen}.
4407	\end{proof}
